mapper.select:
SELECT e.equipment_type AS equipmentType, SUBSTRING(p.planned_date, 1, 6) AS month, COUNT(*) AS totalPlans, SUM(CASE WHEN r.result_id IS NOT NULL THEN 1 ELSE 0 END) AS completedCount, ROUND(100.0 * SUM(CASE WHEN r.result_id IS NOT NULL THEN 1 ELSE 0 END) / COUNT(*), 1) AS completionRate FROM inspection_plans p JOIN equipment e ON p.equipment_code = e.equipment_code LEFT JOIN inspection_results r ON p.plan_id = r.plan_id
AND SUBSTRING(p.planned_date, 1, 6) >= #{dateFrom}
AND SUBSTRING(p.planned_date, 1, 6) <= #{dateTo}
AND e.equipment_type = #{equipmentType}
GROUP BY e.equipment_type, SUBSTRING(p.planned_date, 1, 6) ORDER BY e.equipment_type, month

SELECT
    SUBSTRING(i.incident_datetime, 1, 7) AS month,
    i.incident_type AS incidentType,
    COUNT(*) AS count
FROM incidents i


        AND SUBSTRING(i.incident_datetime, 1, 7) >= #{dateFrom}


        AND SUBSTRING(i.incident_datetime, 1, 7) <= #{dateTo}


        AND i.equipment_code IN (
            SELECT equipment_code FROM equipment WHERE equipment_type = #{equipmentType}
        )


GROUP BY SUBSTRING(i.incident_datetime, 1, 7), i.incident_type
ORDER BY month, incident_type

SELECT e.equipment_code AS equipmentCode, e.equipment_name AS equipmentName, e.equipment_type AS equipmentType, COUNT(*) AS incidentCount FROM incidents i JOIN equipment e ON i.equipment_code = e.equipment_code
AND SUBSTRING(i.incident_datetime, 1, 7) >= #{dateFrom}
AND SUBSTRING(i.incident_datetime, 1, 7) <= #{dateTo}
AND e.equipment_type = #{equipmentType}
GROUP BY e.equipment_code, e.equipment_name, e.equipment_type ORDER BY incidentCount DESC LIMIT 10
